namespace sv_b79b7b9493bc41dda388bbc3c2d5792e;

public enum ThemeMode
{
    Light,
    Dark,
    System
}

public record ThemeInfo(ThemeMode Mode, string AccentColor)
{
    public static ThemeInfo Default => new(ThemeMode.Light, "#0d6efd");
}

@using Microsoft.AspNetCore.Components

<span class="theme-indicator" style="color: @Theme?.AccentColor;">
    @GetThemeIcon() @Theme?.Mode
</span>

@code {
    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }

    private string GetThemeIcon() => Theme?.Mode switch
    {
        ThemeMode.Dark => "🌙",
        ThemeMode.System => "💻",
        _ => "☀️"
    };
}

@page "/settings"
@rendermode InteractiveServer
@inject CascadingValueSource<ThemeInfo> ThemeSource

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="mb-3">
    <label class="form-label fw-bold">Theme Mode</label>
    <div>
        @foreach (var mode in Enum.GetValues<ThemeMode>())
        {
            <div class="form-check form-check-inline">
                <input class="form-check-input" type="radio" name="themeMode"
                       id="mode-@mode"
                       checked="@(currentMode == mode)"
                       @onchange="() => SetMode(mode)" />
                <label class="form-check-label" for="mode-@mode">@mode</label>
            </div>
        }
    </div>
</div>

<div class="mb-3">
    <label class="form-label fw-bold" for="accentColor">Accent Color</label>
    <input type="color" class="form-control form-control-color" id="accentColor"
           value="@currentAccent"
           @onchange="OnAccentChanged" />
</div>

<div class="mt-4 p-3 border rounded" style="border-color: @currentAccent !important;">
    <p>Preview: Current theme is <strong>@currentMode</strong> with accent
        <span style="color: @currentAccent;">@currentAccent</span>.
    </p>
</div>

@code {
    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }

    private ThemeMode currentMode;
    private string currentAccent = ThemeInfo.Default.AccentColor;

    protected override void OnParametersSet()
    {
        if (Theme is not null)
        {
            currentMode = Theme.Mode;
            currentAccent = Theme.AccentColor;
        }
    }

    private async Task SetMode(ThemeMode mode)
    {
        currentMode = mode;
        await ApplyTheme();
    }

    private async Task OnAccentChanged(ChangeEventArgs e)
    {
        currentAccent = e.Value?.ToString() ?? currentAccent;
        await ApplyTheme();
    }

    private async Task ApplyTheme()
    {
        var newTheme = new ThemeInfo(currentMode, currentAccent);
        await ThemeSource.NotifyChangedAsync(newTheme);
    }
}

